// Goal: From ∀x (P(x)→Q(x)) and ∀x P(x), derive ∀x Q(x)

PROCEDURE UniversalModusPonens(premise1, premise2):
  // premise1: ∀x (P(x) → Q(x))
  // premise2: ∀x P(x)

  // Step 1: Universal Instantiation on premise2
  // For arbitrary constant a: P(a)
  instanceP <- Instantiate(premise2, 'a')

  // Step 2: Universal Instantiation on premise1
  // For same constant a: P(a) → Q(a)
  instanceImplication <- Instantiate(premise1, 'a')

  // Step 3: Apply Modus Ponens
  // From P(a) and P(a)→Q(a), deduce Q(a)
  conclusionA <- ModusPonens(instanceP, instanceImplication)

  // Step 4: Universal Generalization
  // From Q(a) for arbitrary a, deduce ∀x Q(x)
  finalConclusion <- Generalize(conclusionA, 'x')

  RETURN finalConclusion

// Result: ∀x Q(x)
